@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h2 class="mb-3">Project Board</h2>

@if (_loading)
{
    <div class="d-flex justify-content-center py-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (_error is not null)
{
    <div class="alert alert-danger">
        <strong>Error:</strong> @_error
        <button class="btn btn-sm btn-outline-danger ms-3" @onclick="LoadTasksAsync">Retry</button>
    </div>
}
else
{
    <!-- Summary Stats Bar -->
    <div class="row g-2 mb-3">
        <div class="col">
            <div class="card text-center">
                <div class="card-body py-2">
                    <div class="fw-bold">Total</div>
                    <div class="fs-5">@_allTasks.Count</div>
                </div>
            </div>
        </div>
        @foreach (var col in _columns)
        {
            <div class="col">
                <div class="card text-center">
                    <div class="card-body py-2">
                        <div class="fw-bold">@col</div>
                        <div class="fs-5">@GetTasksForColumn(col).Count</div>
                    </div>
                </div>
            </div>
        }
        <div class="col">
            <div class="card text-center border-danger">
                <div class="card-body py-2">
                    <div class="fw-bold text-danger">Overdue</div>
                    <div class="fs-5 text-danger">@_allTasks.Count(t => t.DueDate.Date < DateTime.Today)</div>
                </div>
            </div>
        </div>
    </div>

    <!-- Search Bar -->
    <div class="mb-3">
        <input type="text" class="form-control" placeholder="Search tasks by title..."
               @bind="_searchQuery" @bind:event="oninput" />
    </div>

    <!-- Kanban Columns -->
    <div class="row g-3">
        @for (int i = 0; i < _columns.Length; i++)
        {
            var colIndex = i;
            var column = _columns[colIndex];
            var tasks = GetFilteredTasksForColumn(column);

            <div class="col-md-4">
                <div class="card h-100">
                    <div class="card-header fw-bold d-flex justify-content-between align-items-center">
                        <span>@column</span>
                        <span class="badge bg-secondary">@GetTasksForColumn(column).Count</span>
                    </div>
                    <div class="card-body d-flex flex-column gap-2 p-2" style="min-height: 200px;">
                        @foreach (var task in tasks)
                        {
                            <div class="card shadow-sm">
                                <div class="card-body p-2">
                                    <div class="fw-semibold mb-1">@task.Title</div>
                                    <div class="text-muted small mb-1">@task.Assignee</div>
                                    <div class="d-flex justify-content-between align-items-center mb-1">
                                        <span class="badge @GetPriorityClass(task.Priority)">@task.Priority</span>
                                        <span class="text-muted small">@task.DueDate.ToString("MMM dd")</span>
                                    </div>
                                    <div class="d-flex justify-content-between mt-1">
                                        @if (colIndex > 0)
                                        {
                                            var leftStatus = _columns[colIndex - 1];
                                            <button class="btn btn-outline-secondary btn-sm"
                                                    disabled="@_moving"
                                                    @onclick="() => MoveTaskAsync(task.Id, leftStatus)">
                                                &larr; Move Left
                                            </button>
                                        }
                                        else
                                        {
                                            <span></span>
                                        }
                                        @if (colIndex < _columns.Length - 1)
                                        {
                                            var rightStatus = _columns[colIndex + 1];
                                            <button class="btn btn-outline-secondary btn-sm"
                                                    disabled="@_moving"
                                                    @onclick="() => MoveTaskAsync(task.Id, rightStatus)">
                                                Move Right &rarr;
                                            </button>
                                        }
                                    </div>
                                </div>
                            </div>
                        }

                        <!-- Add Task Form / Button -->
                        @if (_addingToColumn == column)
                        {
                            <div class="card border-primary mt-auto">
                                <div class="card-body p-2">
                                    <input type="text" class="form-control form-control-sm mb-1"
                                           placeholder="Title" @bind="_newTitle" />
                                    <input type="text" class="form-control form-control-sm mb-1"
                                           placeholder="Assignee" @bind="_newAssignee" />
                                    <select class="form-select form-select-sm mb-1" @bind="_newPriority">
                                        <option value="High">High</option>
                                        <option value="Medium">Medium</option>
                                        <option value="Low">Low</option>
                                    </select>
                                    <input type="date" class="form-control form-control-sm mb-2"
                                           @bind="_newDueDate" />
                                    @if (_addError is not null)
                                    {
                                        <div class="text-danger small mb-1">@_addError</div>
                                    }
                                    <div class="d-flex gap-1">
                                        <button class="btn btn-primary btn-sm flex-fill"
                                                disabled="@_saving"
                                                @onclick="SaveNewTaskAsync">
                                            @(_saving ? "Saving..." : "Save")
                                        </button>
                                        <button class="btn btn-outline-secondary btn-sm flex-fill"
                                                disabled="@_saving"
                                                @onclick="CancelAdd">Cancel</button>
                                    </div>
                                </div>
                            </div>
                        }
                        else
                        {
                            <button class="btn btn-outline-primary btn-sm mt-auto"
                                    @onclick="() => StartAdd(column)">
                                + Add Task
                            </button>
                        }
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    private readonly string[] _columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem> _allTasks = new();
    private bool _loading = true;
    private string? _error;
    private string _searchQuery = string.Empty;
    private bool _moving;

    // Add-task form state
    private string? _addingToColumn;
    private string _newTitle = string.Empty;
    private string _newAssignee = string.Empty;
    private string _newPriority = "Medium";
    private DateTime _newDueDate = DateTime.Today.AddDays(7);
    private bool _saving;
    private string? _addError;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasksAsync();
    }

    private async Task LoadTasksAsync()
    {
        _loading = true;
        _error = null;

        try
        {
            _allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private List<TaskItem> GetTasksForColumn(string status)
        => _allTasks.Where(t => t.Status == status).ToList();

    private List<TaskItem> GetFilteredTasksForColumn(string status)
        => _allTasks
            .Where(t => t.Status == status &&
                        (string.IsNullOrWhiteSpace(_searchQuery) ||
                         t.Title.Contains(_searchQuery, StringComparison.OrdinalIgnoreCase)))
            .ToList();

    private static string GetPriorityClass(string priority) => priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };

    private async Task MoveTaskAsync(int taskId, string newStatus)
    {
        _moving = true;
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var idx = _allTasks.FindIndex(t => t.Id == taskId);
            if (idx >= 0)
            {
                _allTasks[idx] = _allTasks[idx] with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            _error = $"Failed to move task: {ex.Message}";
        }
        finally
        {
            _moving = false;
        }
    }

    private void StartAdd(string column)
    {
        _addingToColumn = column;
        _newTitle = string.Empty;
        _newAssignee = string.Empty;
        _newPriority = "Medium";
        _newDueDate = DateTime.Today.AddDays(7);
        _addError = null;
    }

    private void CancelAdd()
    {
        _addingToColumn = null;
        _addError = null;
    }

    private async Task SaveNewTaskAsync()
    {
        if (string.IsNullOrWhiteSpace(_newTitle))
        {
            _addError = "Title is required.";
            return;
        }

        _saving = true;
        _addError = null;

        try
        {
            var created = await TaskService.CreateTaskAsync(_newTitle.Trim(), _newAssignee.Trim(), _newPriority, _newDueDate);
            // CreateTaskAsync returns with default status; if the column isn't the default, move it.
            if (created.Status != _addingToColumn)
            {
                await TaskService.UpdateTaskStatusAsync(created.Id, _addingToColumn!);
                created = created with { Status = _addingToColumn! };
            }
            _allTasks.Add(created);
            _addingToColumn = null;
        }
        catch (Exception ex)
        {
            _addError = ex.Message;
        }
        finally
        {
            _saving = false;
        }
    }
}

