+            .Where(t => t.Status == status &&
+                        (string.IsNullOrWhiteSpace(_searchQuery) ||
+                         t.Title.Contains(_searchQuery, StringComparison.OrdinalIgnoreCase)))
+            .ToList();
+
+    private static string GetPriorityClass(string priority) => priority switch
+    {
+        "High" => "bg-danger",
+        "Medium" => "bg-warning text-dark",
+        "Low" => "bg-success",
+        _ => "bg-secondary"
+    };
+
+    private async Task MoveTaskAsync(int taskId, string newStatus)
+    {
+        _moving = true;
+        try
+        {
+            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
+            var idx = _allTasks.FindIndex(t => t.Id == taskId);
+            if (idx >= 0)
+            {
+                _allTasks[idx] = _allTasks[idx] with { Status = newStatus };
+            }
+        }
+        catch (Exception ex)
+        {
+            _error = $"Failed to move task: {ex.Message}";
+        }
+        finally
+        {
+            _moving = false;
+        }
+    }
+
+    private void StartAdd(string column)
+    {
+        _addingToColumn = column;
+        _newTitle = string.Empty;
+        _newAssignee = string.Empty;
+        _newPriority = "Medium";
+        _newDueDate = DateTime.Today.AddDays(7);
+        _addError = null;
+    }
+
+    private void CancelAdd()
+    {
+        _addingToColumn = null;
+        _addError = null;
+    }
+
+    private async Task SaveNewTaskAsync()
+    {
+        if (string.IsNullOrWhiteSpace(_newTitle))
+        {
+            _addError = "Title is required.";
+            return;
+        }
+
+        _saving = true;
+        _addError = null;
+
+        try
+        {
+            var created = await TaskService.CreateTaskAsync(_newTitle.Trim(), _newAssignee.Trim(), _newPriority, _newDueDate);
+            // CreateTaskAsync returns with default status; if the column isn't the default, move it.
+            if (created.Status != _addingToColumn)
+            {
+                await TaskService.UpdateTaskStatusAsync(created.Id, _addingToColumn!);
+                created = created with { Status = _addingToColumn! };
+            }
+            _allTasks.Add(created);
+            _addingToColumn = null;
+        }
+        catch (Exception ex)
+        {
+            _addError = ex.Message;
+        }
+        finally
+        {
+            _saving = false;
+        }
+    }
+}
